'use client';

import { useState } from 'react';
import DashboardLayout from '@/src/components/DashboardLayout';
import FileUpload from '@/src/components/FileUpload';
import { documentService } from '@/src/services/api';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'motion/react';
import { CheckCircle2, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

export default function UploadPage() {
  const [isUploading, setIsUploading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isSuccess, setIsSuccess] = useState(false);
  const router = useRouter();

  const handleUpload = async (file: File, hash: string) => {
    setIsUploading(true);
    try {
      // Mocking upload
      for (let i = 0; i <= 100; i += 10) {
        setProgress(i);
        await new Promise(resolve => setTimeout(resolve, 200));
      }
      setIsSuccess(true);
      setTimeout(() => {
        router.push('/dashboard');
      }, 2000);
    } catch (err) {
      console.error(err);
      setIsUploading(false);
    }
  };

  return (
    <DashboardLayout>
      <div className="max-w-2xl mx-auto space-y-8">
        <div className="flex items-center gap-4">
          <Link href="/dashboard" className="p-2 hover:bg-white/5 rounded-xl transition-all">
            <ArrowLeft className="w-6 h-6 text-zinc-400" />
          </Link>
          <div>
            <h1 className="text-4xl font-black tracking-tight">Upload</h1>
            <p className="text-zinc-500">Securely hash and store your document</p>
          </div>
        </div>

        <AnimatePresence mode="wait">
          {!isSuccess ? (
            <motion.div
              key="upload-form"
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
            >
              <div className="bg-white/5 border border-white/10 rounded-3xl p-8">
                <FileUpload 
                  onUpload={handleUpload} 
                  isUploading={isUploading} 
                  progress={progress} 
                />
                
                <div className="mt-8 p-6 bg-amber-500/5 border border-amber-500/20 rounded-2xl">
                  <h4 className="text-amber-500 font-bold text-sm mb-2 flex items-center gap-2">
                    <CheckCircle2 className="w-4 h-4" />
                    Security Note
                  </h4>
                  <p className="text-xs text-zinc-400 leading-relaxed">
                    Your document is hashed locally using SHA-256. Only the cryptographic hash and file metadata are used for verification. Ensure you keep the original file unchanged for future verification.
                  </p>
                </div>
              </div>
            </motion.div>
          ) : (
            <motion.div
              key="success"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="bg-emerald-500/10 border border-emerald-500/20 rounded-3xl p-12 text-center flex flex-col items-center gap-6"
            >
              <div className="w-20 h-20 rounded-full bg-emerald-500 flex items-center justify-center shadow-lg shadow-emerald-500/40">
                <CheckCircle2 className="w-10 h-10 text-white" />
              </div>
              <div>
                <h2 className="text-3xl font-black mb-2">Upload Successful</h2>
                <p className="text-zinc-400">Your document has been hashed and secured.</p>
              </div>
              <p className="text-xs text-zinc-500 animate-pulse">Redirecting to dashboard...</p>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </DashboardLayout>
  );
}
